function _initializeEIP712(
    string memory name,
    string memory version
)
    internal
{
    domainSeparator = keccak256(
        abi.encode(
            EIP712_DOMAIN_TYPEHASH,
            keccak256(bytes(name)),
            keccak256(bytes(version)),
            address(this),
            bytes32(getChainId())
        )
    );
}

function setFeesCollectorCutPerMillion(uint256 _feesCollectorCutPerMillion) public onlyOwner {
  feesCollectorCutPerMillion = _feesCollectorCutPerMillion;

  require(
    feesCollectorCutPerMillion + royaltiesCutPerMillion < 1000000,
    "MarketplaceV2#setFeesCollectorCutPerMillion: TOTAL_FEES_MUST_BE_BETWEEN_0_AND_999999"
  );

  emit ChangedFeesCollectorCutPerMillion(feesCollectorCutPerMillion);
}

function setFeesCollector(address _newFeesCollector) onlyOwner public {
    require(_newFeesCollector != address(0), "MarketplaceV2#setFeesCollector: INVALID_FEES_COLLECTOR");

    emit FeesCollectorSet(feesCollector, _newFeesCollector);
    feesCollector = _newFeesCollector;
}

function setOwnerCutPerMillion(uint256 _ownerCutPerMillion) public onlyOwner {
  require(_ownerCutPerMillion < 1000000, "The owner cut should be between 0 and 999,999");

  ownerCutPerMillion = _ownerCutPerMillion;
  emit ChangedOwnerCutPerMillion(ownerCutPerMillion);
}

function withdrawRewards(uint256 _maxAmount) external returns (uint256 amount) {
    require(msg.sender == LIDO, "ONLY_LIDO_CAN_WITHDRAW");

    uint256 balance = address(this).balance;
    amount = (balance > _maxAmount) ? _maxAmount : balance;
    if (amount > 0) {
        ILido(LIDO).receiveELRewards{value: amount}();
    }
    return amount;
}

constructor(address _locator, address _stETH)
        Versioned()
    {
        if (_locator == address(0)) revert ZeroAddress("_locator");
        if (_stETH == address(0)) revert ZeroAddress("_stETH");

        LOCATOR = ILidoLocator(_locator);
        LIDO = ILido(_stETH);
    }

function initialize(address _admin, bool _isMigrationAllowed) external {
    if (_admin == address(0)) revert ZeroAddress("_admin");

    _initializeContractVersionTo(1);

    _grantRole(DEFAULT_ADMIN_ROLE, _admin);

    _storageV3Upgrade().isMigrationAllowed = _isMigrationAllowed;
}

constructor(address _lido, address _treasury, address _triggerableWithdrawalsGateway) {
    _onlyNonZeroAddress(_lido);
    _onlyNonZeroAddress(_treasury);
    _onlyNonZeroAddress(_triggerableWithdrawalsGateway);

    LIDO = ILido(_lido);
    TREASURY = _treasury;
    TRIGGERABLE_WITHDRAWALS_GATEWAY = _triggerableWithdrawalsGateway;
}

function _setFeeRecipient(address _newFeeRecipient) internal {
    _requireNotZero(_newFeeRecipient);
    if (_newFeeRecipient == feeRecipient) revert SameRecipient();

    address oldFeeRecipient = feeRecipient;
    feeRecipient = _newFeeRecipient;
    emit FeeRecipientSet(msg.sender, oldFeeRecipient, _newFeeRecipient);
}

constructor(address initialOwner_, address tokenRateProvider_) {
    if (initialOwner_ == address(0)) {
        revert ErrorZeroAddressOwner();
    }
    if (tokenRateProvider_ == address(0)) {
        revert ErrorZeroAddressTokenRateProvider();
    }
    _transferOwnership(initialOwner_);
    TOKEN_RATE_PROVIDER = tokenRateProvider_;
}

function removeObserver(address observer_) external onlyOwner {
    uint256 observerIndexToRemove = _observerIndex(observer_);

    if (observerIndexToRemove == INDEX_NOT_FOUND) {
        revert ErrorNoObserverToRemove();
    }
    if (observerIndexToRemove != observers.length - 1) {
        observers[observerIndexToRemove] = observers[observers.length - 1];
    }
    observers.pop();

    emit ObserverRemoved(observer_);
}

function getExtensions() external view override returns (address[] memory extensions) {
    extensions = new address[](_extensions.length());
    for (uint256 i; i < _extensions.length();) {
        extensions[i] = _extensions.at(i);
        unchecked {
            ++i;
        }
    }
    return extensions;
}

function _registerExtension(address extension, string calldata baseURI, bool baseURIIdentical) internal virtual {
    require(extension != address(this) && extension.isContract(), "Invalid");
    emit ExtensionRegistered(extension, msg.sender);
    _extensionBaseURI[extension] = baseURI;
    _extensionBaseURIIdentical[extension] = baseURIIdentical;
    _extensions.add(extension);
    _setApproveTransferExtension(extension, true);
}

function _blacklistExtension(address extension) internal {
    require(extension != address(0) && extension != address(this), "Cannot blacklist yourself");
    if (_extensions.contains(extension)) {
        emit ExtensionUnregistered(extension, msg.sender);
        _extensions.remove(extension);
    }
    if (!_blacklistedExtensions.contains(extension)) {
        emit ExtensionBlacklisted(extension, msg.sender);
        _blacklistedExtensions.add(extension);
    }
}

function _getRoyaltyInfo(uint256 tokenId, uint256 value) internal view returns (address receiver, uint256 amount) {
    (address payable[] memory receivers, uint256[] memory bps) = _getRoyalties(tokenId);
    require(receivers.length <= 1, "More than 1 royalty receiver");

    if (receivers.length == 0) {
        return (address(this), 0);
    }
    return (receivers[0], bps[0] * value / 10000);
}

function _checkRoyalties(address payable[] calldata receivers, uint256[] calldata basisPoints) private pure {
    require(receivers.length == basisPoints.length, "Invalid input");
    uint256 totalBasisPoints;
    for (uint256 i; i < basisPoints.length;) {
        totalBasisPoints += basisPoints[i];
        unchecked {
            ++i;
        }
    }
    require(totalBasisPoints < 10000, "Invalid total royalties");
}

function _setRoyalties(
    address payable[] calldata receivers,
    uint256[] calldata basisPoints,
    RoyaltyConfig[] storage royalties
) private {
    for (uint256 i; i < basisPoints.length;) {
        royalties.push(RoyaltyConfig({receiver: receivers[i], bps: uint16(basisPoints[i])}));
        unchecked {
            ++i;
        }
    }
}

function _registerExtension(address extension, string calldata baseURI, bool baseURIIdentical) internal override {
    require(_extensionCounter < 0xFFFF, "Too many extensions");
    if (_extensionToIndex[extension] == 0) {
        ++_extensionCounter;
        _extensionToIndex[extension] = _extensionCounter;
        _indexToExtension[_extensionCounter] = extension;
    }
    super._registerExtension(extension, baseURI, baseURIIdentical);
}

function supportsInterface(bytes4 interfaceId)
        public
        view
        virtual
        override(ERC721Core, ERC721CreatorCore, AdminControlUpgradeable)
        returns (bool)
    {
        return ERC721CreatorCore.supportsInterface(interfaceId) || ERC721Core.supportsInterface(interfaceId)
            || AdminControlUpgradeable.supportsInterface(interfaceId);
    }

function approve(address to, uint256 tokenId) public virtual override {
    address owner = ERC721Core.ownerOf(tokenId);
    require(to != owner, "ERC721: approval to current owner");

    require(
        msg.sender == owner || isApprovedForAll(owner, msg.sender),
        "ERC721: approve caller is not token owner or approved for all"
    );

    _approve(to, tokenId);
}

function _decodePaymasterUserOp(
    PackedUserOperation calldata userOp
) internal pure virtual returns (uint48 validAfter, uint48 validUntil, bytes calldata signature) {
    bytes calldata paymasterData = userOp.paymasterData();
    return (uint48(bytes6(paymasterData[0:6])), uint48(bytes6(paymasterData[6:12])), paymasterData[12:]);
}

function _update(address from, address to, uint256 value) internal virtual override {
    if (from != address(0)) {
        uint256 unfrozen = available(from);
        require(unfrozen >= value, ERC20InsufficientUnfrozenBalance(from, value, unfrozen));
    }
    super._update(from, to, value);
}

function _validateExecution(
    address account,
    bytes32 /* salt */,
    bytes32 /* mode */,
    bytes calldata data
) internal virtual override returns (bytes calldata) {
    // Decode ERC7579 single execution calldata to extract the actual function callData
    (, , bytes calldata callData) = ERC7579Utils.decodeSingle(data);

    bytes4 selector = bytes4(callData[0:4]);
    require(isAuthorized(account, selector), ERC7579ExecutorSelectorNotAuthorized(selector));

    return data;
}

function _rawERC7579Validation(
    address account,
    bytes32 hash,
    bytes calldata signature
) internal view virtual override returns (bool) {
    (bytes[] memory signingSigners, bytes[] memory signatures) = abi.decode(signature, (bytes[], bytes[]));
    return
        _validateThreshold(account, signingSigners) &&
        _validateSignatures(account, hash, signingSigners, signatures);
}

function _addSigners(address account, bytes[] memory newSigners) internal virtual {
    for (uint256 i = 0; i < newSigners.length; ++i) {
        bytes memory signer = newSigners[i];
        require(signer.length >= 20, ERC7579MultisigInvalidSigner(signer));
        require(_signersSetByAccount[account].add(signer), ERC7579MultisigAlreadyExists(signer));
        emit ERC7913SignerAdded(account, signer);
    }
}

function _setThreshold(address account, uint64 newThreshold) internal virtual {
    require(newThreshold > 0, ERC7579MultisigZeroThreshold());
    _thresholdByAccount[account] = newThreshold;
    _validateReachableThreshold(account);
    emit ERC7913ThresholdSet(account, newThreshold);
}

function _validateSignatures(
    address account,
    bytes32 hash,
    bytes[] memory signingSigners,
    bytes[] memory signatures
) internal view virtual returns (bool valid) {
    for (uint256 i = 0; i < signingSigners.length; ++i) {
        if (!isSigner(account, signingSigners[i])) {
            return false;
        }
    }
    return hash.areValidSignaturesNow(signingSigners, signatures);
}

function cancel(bytes32 id) public virtual override {
    super.cancel(id);
    if (_operationsIdSet.contains(id)) {
        _operationsIdSet.remove(id);
        delete _operationsMap[id];
    }
    if (_operationsBatchIdSet.contains(id)) {
        _operationsBatchIdSet.remove(id);
        delete _operationsBatchMap[id];
    }
}

function _setRoleAdmin(bytes32 role, bytes32 adminRole) internal virtual {
    AccessControlStorage storage $ = _getAccessControlStorage();
    bytes32 previousAdminRole = getRoleAdmin(role);
    $._roles[role].adminRole = adminRole;
    emit RoleAdminChanged(role, previousAdminRole, adminRole);
}

function __VestingWallet_init(address beneficiary, uint64 startTimestamp, uint64 durationSeconds) internal onlyInitializing {
    __Ownable_init_unchained(beneficiary);
    __VestingWallet_init_unchained(beneficiary, startTimestamp, durationSeconds);
}

function __VestingWallet_init_unchained(address, uint64 startTimestamp, uint64 durationSeconds) internal onlyInitializing {
    VestingWalletStorage storage $ = _getVestingWalletStorage();
    $._start = startTimestamp;
    $._duration = durationSeconds;
}
